CREATE TABLE IF NOT EXISTS fl_clients (
  id                  TEXT PRIMARY KEY,
  nom                 TEXT NOT NULL,
  type                TEXT,
  taille              TEXT,
  "typeProduits"      TEXT,
  rotation            TEXT,
  telephone           TEXT,
  email               TEXT,
  adresse             TEXT,
  ville               TEXT,
  secteur             TEXT,
  zone                TEXT,
  "gpsLat"            NUMERIC,
  "gpsLng"            NUMERIC,
  notes               TEXT,
  "createdBy"         TEXT,
  "createdAt"         TEXT DEFAULT now()::text,
  "prevendeurId"      TEXT,
  "defaultHeureLivraison" TEXT,
  "delaiRecouvrement" TEXT,
  "creditAutorise"    BOOLEAN DEFAULT false,
  "creditStatut"      TEXT,
  "creditSolde"       NUMERIC DEFAULT 0,
  "teamLeadId"        TEXT,
  ice                 TEXT,
  "modalitePaiement"  TEXT,
  "plafondCredit"     NUMERIC,
  segment             TEXT,
  "loyaltyPoints"     NUMERIC DEFAULT 0,
  "loyaltyOptIn"      BOOLEAN DEFAULT false,
  credit              NUMERIC DEFAULT 0,
  actif               BOOLEAN DEFAULT true
);

CREATE TABLE IF NOT EXISTS fl_articles (
  id                  TEXT PRIMARY KEY,
  nom                 TEXT NOT NULL,
  "nomAr"             TEXT,
  famille             TEXT,
  unite               TEXT,
  um                  TEXT,
  "colisageParUM"     NUMERIC,
  "colisageCaisses"   NUMERIC,
  "colisageDemiCaisses" NUMERIC,
  "stockDisponible"   NUMERIC DEFAULT 0,
  "stockDefect"       NUMERIC DEFAULT 0,
  "stockTheorique"    NUMERIC,
  "prixAchat"         NUMERIC,
  "pvMethode"         TEXT DEFAULT 'manuel',
  "pvValeur"          NUMERIC,
  photo               TEXT,
  actif               BOOLEAN DEFAULT true,
  "catalogueVisible"  BOOLEAN DEFAULT true,
  "shelfLifeJours"    NUMERIC,
  "marketplaceActif"  BOOLEAN DEFAULT false
);

-- RLS desactive (comme le reste de l'app, cle anon utilisee directement cote client)
ALTER TABLE fl_clients DISABLE ROW LEVEL SECURITY;
ALTER TABLE fl_articles DISABLE ROW LEVEL SECURITY;



